1	import { describe, it, expect } from "vitest";
2	import { GameOfLife } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should create empty grid", () => {
6	    const gol = new GameOfLife();
7	    expect(gol.getCells()).toEqual([]);
8	  });
9	  it("should add a live cell to the grid", () => {
10	    const gol = new GameOfLife();
11	    gol.addCell(2, 3);
12	    expect(gol.getCells()).toEqual([[2, 3]]);
13	  });
14	  it("should count zero neighbors for isolated cell", () => {
15	    const gol = new GameOfLife();
16	    gol.addCell(5, 5);
17	    expect(gol.countNeighbors(5, 5)).toBe(0);
18	  });
19	  it("should count one neighbor for single adjacent cell", () => {
20	    const gol = new GameOfLife();
21	    gol.addCell(5, 5);
22	    gol.addCell(6, 6);
23	    expect(gol.countNeighbors(5, 5)).toBe(1);
24	  });
25	  it("should count multiple neighbors for adjacent cells", () => {
26	    const gol = new GameOfLife();
27	    gol.addCell(5, 5);
28	    gol.addCell(4, 4);
29	    gol.addCell(4, 5);
30	    gol.addCell(4, 6);
31	    expect(gol.countNeighbors(5, 5)).toBe(3);
32	  });
33	  it("should kill live cell with less than 2 neighbors", () => {
34	    const gol = new GameOfLife();
35	    gol.addCell(5, 5);
36	    gol.addCell(6, 6);
37	    const nextGen = gol.nextGeneration();
38	    expect(nextGen).toEqual([]);
39	  });
40	  it("should keep live cell with 2 neighbors (survival)", () => {
41	    const gol = new GameOfLife();
42	    gol.addCell(5, 5);
43	    gol.addCell(4, 4);
44	    gol.addCell(4, 5);
45	    const nextGen = gol.nextGeneration();
46	    expect(nextGen).toEqual([[5, 5]]);
47	  });
48	  it.todo("should keep live cell with 3 neighbors");
49	  it.todo("should kill live cell with more than 3 neighbors");
50	  it.todo("should resurrect dead cell with exactly 3 neighbors");
51	  it.todo("should advance one generation");
52	  it.todo("should handle negative coordinates");
53	  it.todo("should keep empty grid empty");
54	});
