1	export class GameOfLife {
2	  private cells: [number, number][] = [];
3	
4	  getCells() {
5	    return this.cells;
6	  }
7	
8	  addCell(x: number, y: number) {
9	    this.cells.push([x, y]);
10	  }
11	
12	  countNeighbors(x: number, y: number): number {
13	    let count = 0;
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const nx = x + dx;
18	        const ny = y + dy;
19	        if (this.cells.some(cell => cell[0] === nx && cell[1] === ny)) {
20	          count++;
21	        }
22	      }
23	    }
24	    return count;
25	  }
26	
27	  nextGeneration(): [number, number][] {
28	    return [];
29	  }
30	}
